import React from 'react';

const Certificates = () => {

  return (
    <section id="certificates" className="certificates-section py-5">
      <div className="container">
        <h2 className="text-center mb-4">Certificates</h2>
        <div class="block-separator">
          <div class="certificate-content">
            <h4 class="block-title">Shopware 6 Certified Developer</h4>
            <h5 class="block-subtitle">May 2023</h5>
            <p class="block-content">A Certified Developer has basic knowledge of the technology behind Shopware and its application in projects. Structure and technology of Shopware 6.</p>
          </div>
          <div class="certificate-img">
          <img class="shopware_cetificate" src="https://deep-hyperloop.in/portfolio/public/static/media/images/Certificate/Deepak_Aruldoss_shopware.webp" alt="shopware cetificate" ></img>
          </div>
        </div>

        <div class="block-separator">
            <h4 class="block-title">Diploma (CS)</h4>
            <h5 class="block-subtitle">Valivalam Desikar Polytechnic College, Nagapattinam</h5>
            <p class="block-content">Completed in 2015.</p>
        </div>
      </div>
    </section>
  );
};

export default Certificates;
